// Pursuit logo assets embedded as base64 (white, for use on purple/dark backgrounds)
const PURSUIT_LOGO_FULL_B64 = '';
const PURSUIT_LOGO_MARK_B64 = '';
import './ContentPreview.css';

// Social icons and Pursuit logo from template (template_slides_new.pptx)
const PURSUIT_LOGO_TEMPLATE_B64 = '';
const TWITTER_ICON_B64 = '';
