const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:4000';

/**
 * Content Preview Page
 * Allows staff/admin/volunteers to view and test curriculum content as students see it
 */
function ContentPreview() {
  const user = useAuthStore((s) => s.user);
  const token = useAuthStore((s) => s.token);
  const [searchParams, setSearchParams] = useSearchParams();
  
  const [loading, setLoading] = useState(false);
  const [selectedCohort, setSelectedCohort] = useState(null);
  const [selectedDay, setSelectedDay] = useState(null);
  const [dayContent, setDayContent] = useState(null);
  const [previewMode, setPreviewMode] = useState('readonly'); // 'readonly' or 'interactive'

  // Dialog states for editing
  const [editDialogOpen, setEditDialogOpen] = useState(false);
  const [historyDialogOpen, setHistoryDialogOpen] = useState(false);
  const [goalEditorOpen, setGoalEditorOpen] = useState(false);
  const [moveTaskDialogOpen, setMoveTaskDialogOpen] = useState(false);
  const [deleteTaskDialogOpen, setDeleteTaskDialogOpen] = useState(false);
  const [deleteDayDialogOpen, setDeleteDayDialogOpen] = useState(false);
  const [createTaskDialogOpen, setCreateTaskDialogOpen] = useState(false);
  const [selectedTask, setSelectedTask] = useState(null);
  const [selectedField, setSelectedField] = useState('');
  const [selectedEntityType, setSelectedEntityType] = useState('task');
  const [selectedEntityId, setSelectedEntityId] = useState(null);
  const [taskToDelete, setTaskToDelete] = useState(null);
  const [dayToDelete, setDayToDelete] = useState(null);

  // Upload dialog state
  const [uploadDialogOpen, setUploadDialogOpen] = useState(false);
  const [uploadCohort, setUploadCohort] = useState(null);

  // Sidebar refresh trigger (incremented after day edits to refresh CohortDaySelector)
  const [sidebarRefreshKey, setSidebarRefreshKey] = useState(0);

  // Facilitator notes generation state
  const [generatingNotes, setGeneratingNotes] = useState(false);

  // Facilitator slides generation state
  const [generatingSlides, setGeneratingSlides] = useState(false);

  // Check if user has preview access and edit permissions via the permission system
  const { canAccessPage, canUseFeature } = usePermissions();
  const hasPreviewAccess = canAccessPage('content_preview');
  const canEdit = canUseFeature('edit_curriculum');

  const loadDayContent = async (dayId) => {
    try {
      setLoading(true);
      const response = await axios.get(
        `${API_URL}/api/curriculum/days/${dayId}/full-details?cohort=${encodeURIComponent(selectedCohort?.cohort_name || '')}&t=${Date.now()}`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      const dayData = response.data;
      setDayContent(dayData);
      // Set selectedDay to the day object within dayData (has .id property)
      setSelectedDay(dayData.day);
      
      // Update URL params
      searchParams.set('day', dayId);
      setSearchParams(searchParams);
    } catch (error) {
      console.error('Error loading day content:', error);
      Swal.fire({
        icon: 'error',
        title: 'Error',
        text: error.response?.data?.error || 'Failed to load day content',
        confirmButtonColor: '#4242EA'
      });
    } finally {
      setLoading(false);
    }
  };

  const handleCohortSelect = (cohort) => {
    setSelectedCohort(cohort);
    setSelectedDay(null);
    setDayContent(null);
    setPreviewMode('readonly');
    
    // Update URL params
    searchParams.set('cohort', encodeURIComponent(JSON.stringify(cohort)));
    searchParams.delete('day');
    setSearchParams(searchParams);
  };

  const handleDaySelect = (day) => {
    loadDayContent(day.id);
  };

  const handleClearTestData = async () => {
    const result = await Swal.fire({
      title: 'Clear Test Data?',
      html: `
        <p>This will delete all your preview data:</p>
        <ul style="text-align: left; margin: 1rem 0;">
          <li>💬 Conversation messages</li>
          <li>🧵 Conversation threads</li>
          <li>📝 Task submissions</li>
          <li>📊 Assessment submissions</li>
          <li>📈 Progress tracking</li>
          <li>📋 Survey responses</li>
        </ul>
        <p><strong>This action cannot be undone.</strong></p>
      `,
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#EF4444',
      cancelButtonColor: '#6B7280',
      confirmButtonText: 'Yes, clear my test data',
      cancelButtonText: 'Cancel'
    });

    if (!result.isConfirmed) return;

    try {
      setLoading(true);
      const response = await axios.delete(
        `${API_URL}/api/preview/clear-my-data`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      const { deletedCount, details } = response.data;
      const detailsText = [
        details.messages > 0 && `${details.messages} conversation message(s)`,
        details.taskThreads > 0 && `${details.taskThreads} task thread(s)`,
        details.threads > 0 && `${details.threads} thread(s)`,
        details.submissions > 0 && `${details.submissions} task submission(s)`,
        details.previewSubmissions > 0 && `${details.previewSubmissions} preview submission(s)`,
        details.legacySubmissions > 0 && `${details.legacySubmissions} legacy submission(s)`,
        details.assessmentSubmissions > 0 && `${details.assessmentSubmissions} assessment submission(s)`,
        details.taskProgress > 0 && `${details.taskProgress} task progress record(s)`,
        details.feedback > 0 && `${details.feedback} survey response(s)`,
        details.submissionImagesFound > 0 && `${details.submissionImagesDeleted || 0}/${details.submissionImagesFound} submission image(s) deleted`
      ].filter(Boolean).join('<br>');
      
      // Clear localStorage survey progress data
      let localStorageCleared = 0;
      const keysToRemove = [];
      for (let i = 0; i < localStorage.length; i++) {
        const key = localStorage.key(i);
        if (key && key.startsWith('survey_progress_')) {
          keysToRemove.push(key);
        }
      }
      keysToRemove.forEach(key => {
        localStorage.removeItem(key);
        localStorageCleared++;
      });
      
      if (localStorageCleared > 0) {
        console.log(`Cleared ${localStorageCleared} survey progress items from localStorage`);
      }
      
      await Swal.fire({
        icon: 'success',
        title: 'Test Data Cleared',
        html: deletedCount > 0 || localStorageCleared > 0
          ? `
            <p>Successfully deleted <strong>${deletedCount}</strong> preview record(s):</p>
            <div style="text-align: left; margin: 1rem 0; font-size: 0.9rem;">
              ${detailsText}
              ${localStorageCleared > 0 ? `<br>${localStorageCleared} cached survey progress item(s)` : ''}
            </div>
          `
          : '<p>No test data found to delete.</p>',
        confirmButtonColor: '#4242EA'
      });
      
      // Navigate back to the overview/cohort selection
      setSelectedDay(null);
      setDayContent(null);
      setPreviewMode('readonly');
      
      // Clear URL params to go back to cohort overview
      searchParams.delete('day');
      setSearchParams(searchParams);
      
    } catch (error) {
      console.error('Error clearing test data:', error);
      Swal.fire({
        icon: 'error',
        title: 'Error',
        text: 'Failed to clear test data',
        confirmButtonColor: '#4242EA'
      });
    } finally {
      setLoading(false);
    }
  };

  // Task editing handlers
  const handleEditTask = (task) => {
    setSelectedTask(task);
    setEditDialogOpen(true);
  };

  const handleViewHistory = (task) => {
    setSelectedTask(task);
    setSelectedField('task_title'); // Default field
    setSelectedEntityType('task');
    setSelectedEntityId(task.id);
    setHistoryDialogOpen(true);
  };

  const handleViewFieldHistory = (fieldName, entityType = 'task', entityId = null) => {
    setSelectedField(fieldName);
    setSelectedEntityType(entityType);
    setSelectedEntityId(entityId || selectedTask?.id);
    setHistoryDialogOpen(true);
  };

  const handleSaveTask = async (taskId, formData) => {
    // Prepare task updates
    const taskUpdates = {
      task_title: formData.task_title,
      task_description: formData.task_description,
      intro: formData.intro,
      questions: formData.questions,
      linked_resources: formData.linked_resources,
      conclusion: formData.conclusion,
      deliverable: formData.deliverable,
      deliverable_type: formData.deliverable_type,
      should_analyze: formData.should_analyze,
      analyze_deliverable: formData.analyze_deliverable,
      task_mode: formData.task_mode,
      task_type: formData.task_type,
      feedback_slot: formData.feedback_slot,
      assessment_id: formData.assessment_id,
      persona: formData.persona,
      ai_helper_mode: formData.ai_helper_mode
    };
    
    console.log('Saving task:', taskId, 'with updates:', taskUpdates);
    console.log('Cohort:', selectedCohort?.cohort_name);
    
    // Update task - let errors propagate to the dialog's catch handler
    const taskResponse = await axios.put(
      `${API_URL}/api/curriculum/tasks/${taskId}/edit?cohort=${encodeURIComponent(selectedCohort?.cohort_name || '')}`,
      taskUpdates,
      { headers: { Authorization: `Bearer ${token}` } }
    );
    
    console.log('Task update response:', taskResponse.status, taskResponse.data);
    
    // Update time block only when a time actually changed
    const task = dayContent.flattenedTasks?.find(t => t.id === taskId);
    if (task && task.block_id) {
      const normalizeTime = (value) => (typeof value === 'string' ? value.slice(0, 5) : '');
      const hasStartTimeChange = normalizeTime(formData.start_time) !== normalizeTime(task.start_time);
      const hasEndTimeChange = normalizeTime(formData.end_time) !== normalizeTime(task.end_time);

      if (hasStartTimeChange || hasEndTimeChange) {
        const blockUpdates = {};
        if (hasStartTimeChange) blockUpdates.start_time = formData.start_time;
        if (hasEndTimeChange) blockUpdates.end_time = formData.end_time;

        await axios.put(
          `${API_URL}/api/curriculum/blocks/${task.block_id}/edit?cohort=${encodeURIComponent(selectedCohort?.cohort_name || '')}`,
          blockUpdates,
          { headers: { Authorization: `Bearer ${token}` } }
        );
      }
    }
    
    // Refresh day content to show updated data
    await loadDayContent(selectedDay.id);
  };

  const handleDeleteTask = (task) => {
    setTaskToDelete(task);
    setDeleteTaskDialogOpen(true);
  };

  const confirmDeleteTask = async () => {
    if (!taskToDelete) return;
    
    try {
      setLoading(true);
      const response = await axios.delete(
        `${API_URL}/api/curriculum/tasks/${taskToDelete.id}`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      if (response.status === 200) {
        toast.success('Task deleted successfully');
        setDeleteTaskDialogOpen(false);
        setTaskToDelete(null);

        // Refresh day content and sidebar
        await loadDayContent(selectedDay.id);
        setSidebarRefreshKey(prev => prev + 1);
      }
    } catch (error) {
      console.error('Error deleting task:', error);
      toast.error(error.response?.data?.error || 'Failed to delete task');
    } finally {
      setLoading(false);
    }
  };

  const handleMoveTask = async (taskId, targetDayId) => {
    try {
      const response = await axios.post(
        `${API_URL}/api/curriculum/tasks/${taskId}/move?cohort=${encodeURIComponent(selectedCohort?.cohort_name || '')}`,
        { targetDayId },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      if (response.status === 200) {
        toast.success('Task moved successfully');
        // Refresh day content and sidebar (task moved between days)
        await loadDayContent(selectedDay.id);
        setSidebarRefreshKey(prev => prev + 1);
      }
    } catch (error) {
      console.error('Error moving task:', error);
      toast.error('Failed to move task');
      throw error;
    }
  };

  const handleRevertField = async (entityType, entityId, fieldName, value) => {
    try {
      const response = await axios.post(
        `${API_URL}/api/curriculum/revert?cohort=${encodeURIComponent(selectedCohort?.cohort_name || '')}`,
        {
          entityType,
          entityId,
          fieldName,
          revertToValue: value
        },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      if (response.status === 200) {
        toast.success('Field reverted successfully');
        // Refresh day content
        await loadDayContent(selectedDay.id);
      }
    } catch (error) {
      console.error('Error reverting field:', error);
      toast.error('Failed to revert field');
      throw error;
    }
  };

  // Day editing handlers
  const handleEditDayGoals = () => {
    setGoalEditorOpen(true);
  };

  const handleSaveGoals = async (goalData) => {
    try {
      const response = await axios.put(
        `${API_URL}/api/curriculum/days/${selectedDay.id}/edit?cohort=${encodeURIComponent(selectedCohort?.cohort_name || '')}`,
        goalData,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      if (response.status === 200) {
        toast.success('Day info updated successfully');
        // Refresh day content
        await loadDayContent(selectedDay.id);
        // Refresh sidebar to reflect date changes
        setSidebarRefreshKey(prev => prev + 1);
      }
    } catch (error) {
      console.error('Error saving day info:', error);
      toast.error('Failed to update day info');
      throw error;
    }
  };

  const handleDeleteDay = () => {
    setDayToDelete(selectedDay);
    setDeleteDayDialogOpen(true);
  };

  const confirmDeleteDay = async () => {
    if (!dayToDelete) return;
    
    try {
      setLoading(true);
      const response = await axios.delete(
        `${API_URL}/api/curriculum/days/${dayToDelete.id}`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      if (response.status === 200) {
        toast.success(`Day ${dayToDelete.day_number} deleted successfully`);

        // Clear selection and refresh
        setSelectedDay(null);
        setDayContent(null);
        setDeleteDayDialogOpen(false);
        setDayToDelete(null);

        // Refresh sidebar to remove deleted day and update cohort day count
        setSidebarRefreshKey(prev => prev + 1);
      }
    } catch (error) {
      console.error('Error deleting day:', error);
      toast.error(error.response?.data?.error || 'Failed to delete day');
    } finally {
      setLoading(false);
    }
  };

  // Task creation handler
  const handleAddTask = () => {
    setCreateTaskDialogOpen(true);
  };

  const handleGenerateNotes = async () => {
    if (!dayContent) return;
    setGeneratingNotes(true);
    const controller = new AbortController();
    try {
      const response = await axios.post(
        `${API_URL}/api/content/generate-facilitator-notes-doc`,
        { dayContent },
        { headers: { Authorization: `Bearer ${token}` }, signal: controller.signal }
      );

      const notesText = response.data.notes;
      const day = dayContent.day;

      // Lazy-load jsPDF (~300KB) only when needed
      const { jsPDF } = await import('jspdf');

      const doc = new jsPDF({ unit: 'pt', format: 'letter' });
      const pageWidth = doc.internal.pageSize.getWidth();
      const pageHeight = doc.internal.pageSize.getHeight();
      const margin = 50;
      const usableWidth = pageWidth - margin * 2;
      let y = margin;

      // Render a line of text, handling **bold** inline markers
      const addText = (text, fontSize, isBold = false, color = [30, 30, 30]) => {
        doc.setFontSize(fontSize);
        doc.setTextColor(...color);
        const lineHeight = fontSize * 1.4;

        // Parse **bold** segments
        const segments = [];
        const boldRegex = /\*\*([^*]+)\*\*/g;
        let lastIdx = 0;
        let match;
        while ((match = boldRegex.exec(text)) !== null) {
          if (match.index > lastIdx) {
            segments.push({ text: text.slice(lastIdx, match.index), bold: false });
          }
          segments.push({ text: match[1], bold: true });
          lastIdx = boldRegex.lastIndex;
        }
        if (lastIdx < text.length) {
          segments.push({ text: text.slice(lastIdx), bold: false });
        }

        // If no bold markers, render simply
        if (segments.length <= 1 && !segments[0]?.bold) {
          doc.setFont('helvetica', isBold ? 'bold' : 'normal');
          const lines = doc.splitTextToSize(segments[0]?.text || text, usableWidth);
          for (const line of lines) {
            if (y + lineHeight > pageHeight - margin) { doc.addPage(); y = margin; }
            doc.text(line, margin, y);
            y += lineHeight;
          }
          return;
        }

        // Render segments with inline bold: measure and wrap manually
        let x = margin;
        for (const seg of segments) {
          doc.setFont('helvetica', seg.bold ? 'bold' : (isBold ? 'bold' : 'normal'));
          const words = seg.text.split(/( +)/);
          for (const word of words) {
            if (!word) continue;
            const wordWidth = doc.getTextWidth(word);
            if (x + wordWidth > pageWidth - margin && x > margin) {
              y += lineHeight;
              x = margin;
              if (y + lineHeight > pageHeight - margin) { doc.addPage(); y = margin; }
            }
            doc.text(word, x, y);
            x += wordWidth;
          }
        }
        y += lineHeight;
      };

      const addSpacing = (pts = 8) => { y += pts; };

      // Normalise the day header line so it always reads "Day X - Cohort Name"
      const cohortName = day?.cohort || '';
      const normalisedText = notesText.replace(
        /^Day (\d+)\s*-[^\n]*/m,
        `Day $1${cohortName ? ` - ${cohortName}` : ''}`
      );

      // Parse and render the notes text
      const rawLines = normalisedText.split('\n');
      for (const line of rawLines) {
        const trimmed = line.trim();
        if (!trimmed) {
          addSpacing(6);
          continue;
        }

        // Separator line — any line of only dashes (e.g. "------")
        if (/^-{2,}$/.test(trimmed)) {
          addSpacing(6);
          addText('------', 10, false, [180, 180, 180]);
          addSpacing(6);
        }
        // Day header line — "Day 1 - Cohort Name"
        else if (/^Day \d+(\s*-|$)/.test(trimmed)) {
          addSpacing(4);
          addText(trimmed, 14, true, [30, 30, 30]);
          addSpacing(4);
        }
        // Time block header — "10:00am - 1:00pm: Block Name"
        else if (/^\d{1,2}:\d{2}(am|pm)\s*-\s*\d{1,2}:\d{2}(am|pm)\s*:/i.test(trimmed)) {
          addSpacing(10);
          addText(trimmed, 11, true, [30, 30, 30]);
          addSpacing(2);
        }
        // Section labels — render just the label bold, then the content on the next line at normal weight
        else if (/^(Facilitator sets context|Facilitator notes|Platform notes|Tool notes)\s*:/i.test(trimmed)) {
          const colonIdx = trimmed.indexOf(':');
          const label = trimmed.slice(0, colonIdx + 1);
          const content = trimmed.slice(colonIdx + 1).trim();
          addSpacing(6);
          addText(label, 10, true, [50, 50, 50]);
          if (content) {
            addSpacing(1);
            addText(content, 10, false, [60, 60, 60]);
          }
          addSpacing(2);
        }
        // Bullet points
        else if (/^[-•]/.test(trimmed) || /^\d+[.)]\s/.test(trimmed) || /^[ivxlIVXL]+[.)]\s/.test(trimmed) || /^\s{2,}[-•]/.test(line)) {
          const bullet = '•  ' + trimmed.replace(/^[-•]\s+/, '').replace(/^\d+[.)]\s+/, '').replace(/^[ivxlIVXL]+[.)]\s+/, '');
          addText(bullet, 10, false, [60, 60, 60]);
        }
        // Regular text / quoted context
        else {
          addText(trimmed, 10, false, [60, 60, 60]);
        }
      }

      const cohortSlug = cohortName.replace(/\s+/g, '-') || 'cohort';
      const fileName = `facilitator-notes-day-${day?.day_number || 'unknown'}-${cohortSlug}.pdf`;
      doc.save(fileName);
      toast.success('Facilitator notes downloaded!');
    } catch (error) {
      if (error.name === 'CanceledError') return;
      console.error('Error generating facilitator notes:', error);
      toast.error('Failed to generate facilitator notes. Please try again.');
    } finally {
      setGeneratingNotes(false);
    }
  };

  const handleGenerateSlides = async () => {
    if (!dayContent) return;
    setGeneratingSlides(true);
    try {
      // Step 1: Get AI-structured slide content from backend
      const response = await axios.post(
        `${API_URL}/api/content/generate-facilitator-slides`,
        { dayContent },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      const { slideContent } = response.data;
      const { agendaItems = [], tasks: slideTasks = [] } = slideContent;

      const day = dayContent.day;
      const flatTasks = dayContent.flattenedTasks || [];
      const cohortName = day?.cohort || '';
      const dayNumber = day?.day_number || '';
      const dailyGoal = day?.daily_goal || '';

      const formatSlideDate = (dateStr) => {
        if (!dateStr) return '';
        const d = new Date(dateStr);
        if (isNaN(d.getTime())) return '';
        return d.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
      };

      const formatTime = (timeStr) => {
        if (!timeStr) return '';
        const [hourStr, minStr] = timeStr.split(':');
        let hour = parseInt(hourStr, 10);
        const min = minStr || '00';
        const ampm = hour >= 12 ? 'pm' : 'am';
        if (hour > 12) hour -= 12;
        if (hour === 0) hour = 12;
        return `${hour}:${min}${ampm}`;
      };

      const calcBreakMinutes = (startTime, endTime) => {
        if (!startTime || !endTime) return null;
        const [sh, sm] = startTime.split(':').map(Number);
        const [eh, em] = endTime.split(':').map(Number);
        const mins = (eh * 60 + em) - (sh * 60 + sm);
        return mins > 0 ? mins : null;
      };

      const toSentenceCase = (str) => {
        if (!str) return '';
        return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
      };

      // Step 2: Build PPTX
      // Dimensions match template: 10" x 5.625" (Google Slides widescreen)
      const pptx = new PptxGenJS();
      pptx.defineLayout({ name: 'GOOGLE_SLIDES', width: 10, height: 5.625 });
      pptx.layout = 'GOOGLE_SLIDES';

      const PURPLE = '4242EA';
      const WHITE = 'FFFFFF';
      const DARK = '1E1E1E';
      const FONT = 'Proxima Nova';

      // ==========================================
      // SLIDE 1: TITLE (Purple background)
      // ==========================================
      const slide1 = pptx.addSlide();
      slide1.background = { color: PURPLE };

      // Cohort name — top-left
      // Template: x=0.25", y=0.25", w=3.98", h=0.30" — 22pt white
      if (cohortName) {
        slide1.addText(cohortName, {
          x: 0.25, y: 0.25, w: 3.98, h: 0.30,
          color: WHITE, fontSize: 22, fontFace: FONT, margin: 0,
        });
      }

      // Date + Day N + Goal — ONE textbox anchored to bottom (template: x=0.25", y=2.0929", w=4.75", h=3.3271")
      // valign='bottom' means content anchors to the bottom — long goals push earlier content up automatically
      const dateStr = formatSlideDate(day?.day_date);
      const titleBodyLines = [];
      if (dateStr) {
        titleBodyLines.push({ text: dateStr, options: { fontSize: 24, bold: true, breakLine: true } });
      }
      titleBodyLines.push({ text: `Day ${dayNumber}`, options: { fontSize: 42, bold: true, breakLine: true } });
      titleBodyLines.push({ text: '', options: { fontSize: 22, breakLine: true } });
      titleBodyLines.push({ text: "Today's Goal:", options: { fontSize: 22, bold: true, breakLine: true } });
      titleBodyLines.push({ text: dailyGoal || '', options: { fontSize: 22, bold: false } });
      slide1.addText(titleBodyLines, {
        x: 0.25, y: 2.0929, w: 4.75, h: 3.3271,
        color: WHITE, fontFace: FONT, valign: 'bottom', margin: 0,
      });

      // Pursuit logo — top-right corner, flush with slide edges
      // Logo is 1473×609px (ratio 2.419:1); x = 10 - w so right edge aligns with slide
      slide1.addImage({
        data: `data:image/png;base64,${PURSUIT_LOGO_TEMPLATE_B64}`,
        x: 10 - 2.8043, y: 0, w: 2.8043, h: 2.8043 * (609 / 1473),
      });

      // Social footer — bottom-right (exact template positions)
      slide1.addText('pursuit.org', {
        x: 8.4818, y: 4.941, w: 1.1647, h: 0.1617,
        color: WHITE, fontSize: 12, fontFace: FONT, bold: true, align: 'right', margin: 0,
      });
      // Twitter/X icon: x=8.4818", y=5.1837", w=0.2671", h=0.2671"
      slide1.addImage({
        data: `data:image/png;base64,${TWITTER_ICON_B64}`,
        x: 8.4818, y: 5.1837, w: 0.2671, h: 0.2671,
      });
      // @joinpursuit: x=8.7448", y=5.1995"
      slide1.addText('@joinpursuit', {
        x: 8.7448, y: 5.1995, w: 1.0617, h: 0.2021,
        color: WHITE, fontSize: 12, fontFace: FONT, margin: 0,
      });
      // Instagram icon: x=7.4993", y=5.2154", w=0.192", h=0.192"
      slide1.addImage({
        data: `data:image/png;base64,${INSTAGRAM_ICON_B64}`,
        x: 7.4993, y: 5.2154, w: 0.192, h: 0.192,
      });
      // @pursuit: x=7.7538", y=5.1937"
      slide1.addText('@pursuit', {
        x: 7.7538, y: 5.1937, w: 0.7543, h: 0.2021,
        color: WHITE, fontSize: 12, fontFace: FONT, margin: 0,
      });

      // ==========================================
      // SLIDE 2: AGENDA (White background)
      // ==========================================
      const slide2 = pptx.addSlide();

      // "Agenda" title
      // Template: x=0.25", y=0.25", w=3.98", h=0.38" — 28pt bold #4242EA
      slide2.addText('Agenda', {
        x: 0.25, y: 0.25, w: 3.98, h: 0.38,
        color: PURPLE, fontSize: 28, fontFace: FONT, bold: true, margin: 0,
      });

      // Agenda items — no bolding, plain text
      const cappedAgenda = agendaItems.slice(0, 10);
      const agendaItemH = Math.min(3.89 / Math.max(cappedAgenda.length, 1), 0.35);
      cappedAgenda.forEach((item, i) => {
        const yPos = 1.0 + i * agendaItemH;
        slide2.addText(`${i + 1}.`, {
          x: 0.25, y: yPos, w: 0.54, h: agendaItemH,
          color: DARK, fontSize: 22, fontFace: FONT, valign: 'top', margin: 0,
        });
        slide2.addText(item, {
          x: 0.79, y: yPos, w: 8.96, h: agendaItemH,
          color: DARK, fontSize: 22, fontFace: FONT, valign: 'top', margin: 0,
        });
      });

      // Bottom-left logo (template layout: x=0.25", y=5.1635", w=0.149", h=0.2159")
      slide2.addImage({
        data: `data:image/png;base64,${PURSUIT_SMALL_LOGO_B64}`,
        x: 0.25, y: 5.1635, w: 0.149, h: 0.2159,
      });

      // Page number — bottom-right (template: x=9.3166", y=5.0562")
      slide2.addText('P.2', {
        x: 9.3166, y: 5.0562, w: 0.4334, h: 0.4304,
        color: DARK, fontSize: 10, fontFace: FONT, align: 'right', margin: 0,
      });

      // ==========================================
      // SLIDES 3+: TASK / BREAK SLIDES
      // ==========================================
      let taskIdx = 0;
      let pageNum = 3;

      flatTasks.forEach((rawTask) => {
        const taskType = rawTask.task_type || rawTask.task_mode || '';
        const isBreak = taskType.toLowerCase() === 'break';

        if (isBreak) {
          // ---- BREAK SLIDE (Slide 4 template: purple bg, centered text) ----
          const breakSlide = pptx.addSlide();
          breakSlide.background = { color: PURPLE };

          const breakMins = calcBreakMinutes(rawTask.start_time, rawTask.end_time);
          breakSlide.addText([
            { text: 'Break time!', options: { fontSize: 90, bold: true, italic: true, breakLine: true } },
            {
              text: breakMins ? `Come back in ${breakMins} minutes` : 'Take a short break',
              options: { fontSize: 40, bold: true, italic: true },
            },
          ], {
            x: 1.437, y: 1.148, w: 7.124, h: 3.327,
            color: WHITE, fontFace: FONT, valign: 'middle', align: 'center', margin: 0,
          });

          pageNum++;
        } else {
          // ---- TASK SLIDE (Slide 3 template) ----
          const taskSlideData = slideTasks[taskIdx] || {};
          taskIdx++;

          const slide = pptx.addSlide();
          const titleText = taskSlideData.taskTitle || rawTask.task_title || '';
          const timeStr = rawTask.start_time && rawTask.end_time
            ? `${formatTime(rawTask.start_time)} – ${formatTime(rawTask.end_time)}`
            : '';
          const taskTypeLabel = toSentenceCase(taskType);
          const deliverableType = (rawTask.deliverable_type || '').toLowerCase();
          const showDeliverable =
            deliverableType !== '' &&
            deliverableType !== 'text' &&
            deliverableType !== 'none' &&
            !!taskSlideData.deliverableSummary;

          // Title spans full slide width so it always fits on one line — no shifting needed
          // "Task N:" label on first line (12pt), title on second line (28pt bold purple)
          slide.addText([
            { text: `Task ${pageNum - 2}:`, options: { fontSize: 12, color: DARK, bold: false, breakLine: true } },
            { text: titleText, options: { fontSize: 28, color: PURPLE, bold: true } },
          ], {
            x: 0.25, y: 0.2302, w: 9.5, h: 0.60,
            fontFace: FONT, margin: 0, valign: 'top',
          });

          // Time + Task Type — always at template Y (no shifting)
          if (timeStr || taskTypeLabel) {
            const timeTypeRuns = [];
            if (timeStr) timeTypeRuns.push({ text: timeStr, options: { breakLine: !!taskTypeLabel } });
            if (taskTypeLabel) timeTypeRuns.push({ text: taskTypeLabel });
            slide.addText(timeTypeRuns, {
              x: 0.25, y: 1.2004, w: 3.4902, h: 0.4039,
              color: DARK, fontSize: 12, fontFace: FONT, margin: 0, valign: 'top',
            });
          }

          // One-sentence goal — always at template Y
          if (taskSlideData.oneLineSummary) {
            const goalText = taskSlideData.oneLineSummary.replace(/\.+$/, '');
            slide.addText(goalText, {
              x: 0.25, y: 1.7921, w: 3.75, h: 2.20,
              color: DARK, fontSize: 22, fontFace: FONT, margin: 0, valign: 'top',
            });
          }

          // Action items — right panel, always at template Y
          const actionItems = (taskSlideData.actionItems || []).slice(0, 5);
          if (actionItems.length > 0) {
            const actionRuns = [];
            actionItems.forEach((item, i) => {
              if (i > 0) actionRuns.push({ text: '\n', options: { fontSize: 18 } });
              const cleanItem = item.replace(/\.+$/, '');
              const colonIdx = cleanItem.indexOf(': ');
              if (colonIdx > -1) {
                actionRuns.push({ text: `${i + 1}. ${cleanItem.slice(0, colonIdx)}`, options: { fontSize: 18, bold: true, color: DARK } });
                actionRuns.push({ text: ' ' + cleanItem.slice(colonIdx + 2), options: { fontSize: 18, bold: false, color: DARK } });
              } else {
                const spaceIdx = cleanItem.indexOf(' ');
                if (spaceIdx > -1) {
                  actionRuns.push({ text: `${i + 1}. ${cleanItem.slice(0, spaceIdx)}`, options: { fontSize: 18, bold: true, color: DARK } });
                  actionRuns.push({ text: cleanItem.slice(spaceIdx), options: { fontSize: 18, bold: false, color: DARK } });
                } else {
                  actionRuns.push({ text: `${i + 1}. ${cleanItem}`, options: { fontSize: 18, bold: false, color: DARK } });
                }
              }
            });
            const actionH = Math.max(1.6969, actionItems.length * 0.34);
            slide.addText(actionRuns, {
              x: 5.0, y: 1.2004, w: 4.75, h: actionH,
              fontFace: FONT, margin: 0, valign: 'top',
            });
          }

          // Deliverable callout — only when deliverable_type is not 'text' or 'none'
          if (showDeliverable) {
            slide.addText('→', {
              x: 0.25, y: 4.4135, w: 0.3054, h: 0.3445,
              color: PURPLE, fontSize: 20, margin: 0, valign: 'top',
            });
            slide.addText(`Don't forget to submit your ${taskSlideData.deliverableSummary.toLowerCase()} in the task!`, {
              x: 0.5852, y: 4.5123, w: 2.7461, h: 0.3445,
              color: PURPLE, fontSize: 12, fontFace: FONT, margin: 0, valign: 'top',
            });
          }

          // Bottom-left logo (template layout: x=0.25", y=5.1635", w=0.149", h=0.2159")
          slide.addImage({
            data: `data:image/png;base64,${PURSUIT_SMALL_LOGO_B64}`,
            x: 0.25, y: 5.1635, w: 0.149, h: 0.2159,
          });

          // Page number — bottom-right (template: x=9.3166", y=5.0562")
          slide.addText(`P.${pageNum}`, {
            x: 9.3166, y: 5.0562, w: 0.4334, h: 0.4304,
            color: DARK, fontSize: 10, fontFace: FONT, align: 'right', margin: 0,
          });

          pageNum++;
        }
      });

      // Step 3: Download as .pptx
      const cohortSlug = cohortName.replace(/\s+/g, '-') || 'cohort';
      const fileName = `facilitator-slides-day-${dayNumber}-${cohortSlug}.pptx`;
      await pptx.writeFile({ fileName });
      toast.success('Facilitator slides downloaded!');
    } catch (error) {
      console.error('Error generating facilitator slides:', error);
      toast.error('Failed to generate facilitator slides. Please try again.');
    } finally {
      setGeneratingSlides(false);
    }
  };


  const handleCreateTask = async (taskData) => {
    try {
      setLoading(true);
      
      // Find or create a time block with the specified times
      let blockId = null;
      
      if (taskData.start_time && taskData.end_time) {
        // Try to find existing time block with these times
        const existingBlock = dayContent?.timeBlocks?.find(block => 
          block.start_time === taskData.start_time && 
          block.end_time === taskData.end_time
        );
        
        if (existingBlock) {
          blockId = existingBlock.id;
        } else {
          // Create new time block
          try {
            const blockResponse = await axios.post(
              `${API_URL}/api/curriculum/blocks`,
              {
                day_id: selectedDay.id,
                start_time: taskData.start_time,
                end_time: taskData.end_time,
                block_category: 'Learning' // Default category
              },
              { headers: { Authorization: `Bearer ${token}` } }
            );
            blockId = blockResponse.data.block.id;
          } catch (blockError) {
            console.error('Error creating time block:', blockError);
            toast.error('Failed to create time block');
            return;
          }
        }
      } else {
        // No times specified, use first available block
        if (dayContent?.timeBlocks && dayContent.timeBlocks.length > 0) {
          blockId = dayContent.timeBlocks[0].id;
        } else if (dayContent?.flattenedTasks && dayContent.flattenedTasks.length > 0) {
          blockId = dayContent.flattenedTasks[0].block_id;
        }
      }

      if (!blockId) {
        toast.error('No time block found for this day. Please specify start and end times.');
        return;
      }

      const response = await axios.post(
        `${API_URL}/api/curriculum/tasks`,
        {
          block_id: blockId,
          task_title: taskData.task_title,
          task_description: taskData.task_description || '',
          task_type: taskData.task_type || 'individual',
          duration_minutes: taskData.duration_minutes || 30,
          
          // Content fields
          intro: taskData.intro || '',
          conclusion: taskData.conclusion || '',
          questions: taskData.questions || [],
          linked_resources: taskData.linked_resources || [],
          
          // Deliverable fields
          deliverable: taskData.deliverable || '',
          deliverable_type: taskData.deliverable_type || 'none',
          deliverable_schema: taskData.deliverable_schema || null,
          
          // Smart task fields
          task_mode: taskData.task_mode || 'basic',
          conversation_model: taskData.conversation_model || null,
          persona: taskData.persona || null,
          ai_helper_mode: taskData.ai_helper_mode || null,
          feedback_slot: taskData.feedback_slot || null,
          assessment_id: taskData.assessment_id || null,
          
          // Analysis fields
          should_analyze: taskData.should_analyze || false,
          analyze_deliverable: taskData.analyze_deliverable || false,
          analysis_rubric: taskData.analysis_rubric || null
        },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      if (response.status === 201) {
        toast.success('Task created successfully');
        setCreateTaskDialogOpen(false);
        // Refresh day content and sidebar
        await loadDayContent(selectedDay.id);
        setSidebarRefreshKey(prev => prev + 1);
      }
    } catch (error) {
      console.error('Error creating task:', error);
      toast.error(error.response?.data?.error || 'Failed to create task');
    } finally {
      setLoading(false);
    }
  };

  // Upload curriculum handlers
  const handleUploadCurriculum = (cohort) => {
    setUploadCohort(cohort);
    setUploadDialogOpen(true);
  };

  const handleUploadComplete = () => {
    // Refresh sidebar to show new/updated days and update cohort day count
    setSidebarRefreshKey(prev => prev + 1);
    // If a day is currently selected, reload its content
    if (selectedDay?.id) {
      loadDayContent(selectedDay.id);
    }
  };

  // Access denied view
  if (!hasPreviewAccess) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="bg-white p-8 rounded-lg shadow-md max-w-md">
          <h2 className="text-2xl font-bold text-slate-900 mb-4 font-proxima">Access Denied</h2>
          <p className="text-slate-600 font-proxima">
            You don't have permission to access content preview. Only staff, admin, and volunteer users can view this page.
          </p>
        </div>
      </div>
    );
  }

  // Interactive mode - render Learning component directly (no Layout)
  if (previewMode === 'interactive' && dayContent) {
    return (
      <div className="h-screen flex flex-col">
        {/* Preview Mode Banner */}
        <div className="preview-banner bg-blue-600 text-white px-6 py-3 z-50 shadow-md flex-shrink-0">
          <div className="max-w-7xl mx-auto flex items-center justify-between">
            <div className="flex items-center gap-3">
              <AlertCircle className="h-5 w-5" />
              <span className="font-semibold font-proxima">
                🔍 PREVIEW MODE - Interactive
              </span>
              <span className="text-blue-100 font-proxima">
                {selectedCohort?.cohort_name} • Day {dayContent.day?.day_number}
              </span>
            </div>
            <div className="flex items-center gap-3">
              <button
                onClick={() => setPreviewMode('readonly')}
                className="text-sm bg-white text-blue-600 hover:bg-blue-50 px-4 py-1 rounded font-proxima transition-colors font-semibold"
              >
                ← Back to Overview
              </button>
              <button
                onClick={handleClearTestData}
                className="text-sm bg-blue-500 hover:bg-blue-400 px-4 py-1 rounded font-proxima transition-colors"
              >
                Clear My Test Data
              </button>
            </div>
          </div>
        </div>
        
        {/* Learning Preview - takes remaining height */}
        <div className="flex-1 overflow-hidden">
          <LearningPreview
            dayId={dayContent.day?.id}
            cohort={selectedCohort?.cohort_name || dayContent.day?.cohort || ''}
            onBack={() => setPreviewMode('readonly')}
          />
        </div>
      </div>
    );
  }

  // Read-only mode - show selector and content overview
  return (
    <>
      {loading && <LoadingCurtain />}
      
      <div className="content-preview-container h-screen bg-slate-50 flex flex-col overflow-hidden">
        {/* Preview Mode Banner */}
        <div className="preview-banner bg-blue-600 text-white px-6 py-3 z-50 shadow-md flex-shrink-0">
          <div className="max-w-7xl mx-auto flex items-center justify-between">
            <div className="flex items-center gap-3">
              <AlertCircle className="h-5 w-5" />
              <span className="font-semibold font-proxima">
                🔍 PREVIEW MODE
              </span>
              <span className="text-blue-100 font-proxima">
                Select a cohort and day to preview content
              </span>
            </div>
            <div className="flex items-center gap-3">
              {dayContent && (
                <button
                  onClick={() => setPreviewMode('interactive')}
                  className="text-sm bg-white text-blue-600 hover:bg-blue-50 px-4 py-1 rounded font-proxima transition-colors font-semibold"
                >
                  ▶ Enter Interactive Mode
                </button>
              )}
              <button
                onClick={handleClearTestData}
                className="text-sm bg-blue-500 hover:bg-blue-400 px-4 py-1 rounded font-proxima transition-colors"
              >
                Clear My Test Data
              </button>
            </div>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="flex flex-1 overflow-hidden">
          {/* Left: Cohort & Day Selector */}
          <div className="w-80 bg-white border-r border-slate-200 flex flex-col">
            <CohortDaySelector
              token={token}
              selectedCohort={selectedCohort}
              selectedDay={selectedDay}
              onCohortSelect={handleCohortSelect}
              onDaySelect={handleDaySelect}
              onUploadCurriculum={handleUploadCurriculum}
              canEdit={canEdit}
              refreshTrigger={sidebarRefreshKey}
            />
          </div>

          {/* Middle: Content Display */}
          <div className="flex-1 overflow-y-auto">
            {!dayContent ? (
              <div className="flex items-center justify-center h-96">
                <div className="text-center">
                  <h3 className="text-xl font-bold text-slate-900 mb-2 font-proxima">
                    Select a Day to Preview
                  </h3>
                  <p className="text-slate-600 font-proxima">
                    Choose a cohort and day from the left sidebar to view content
                  </p>
                </div>
              </div>
            ) : (
              <div className="p-8">
                <div className="max-w-4xl mx-auto">
                  {/* Day Header */}
                  <div className="mb-8">
                    <div className="flex items-center justify-between mb-4">
                      <div>
                        <h1 className="text-3xl font-bold text-slate-900 font-proxima">
                          Day {dayContent.day?.day_number}
                        </h1>
                        <p className="text-slate-600 font-proxima">
                          {dayContent.day?.day_date && new Date(dayContent.day.day_date).toLocaleDateString('en-US', { 
                            weekday: 'long', 
                            year: 'numeric', 
                            month: 'long', 
                            day: 'numeric' 
                          })}
                        </p>
                      </div>
                      <div className="flex items-center gap-2">
                        <div className="text-right mr-4">
                          <div className="text-sm text-slate-600 font-proxima">
                            {dayContent.day?.cohort}
                          </div>
                          <div className="text-sm font-medium text-slate-900 font-proxima">
                            Week {dayContent.day?.week} • {dayContent.day?.level}
                          </div>
                        </div>
                        <Button
                          size="sm"
                          onClick={handleGenerateNotes}
                          disabled={generatingNotes || generatingSlides}
                          className="bg-[#4242EA] hover:bg-[#3535D1] font-proxima"
                        >
                          <FileText className="h-4 w-4 mr-1" />
                          {generatingNotes ? 'Generating...' : 'Generate Notes'}
                        </Button>
                        <Button
                          size="sm"
                          onClick={handleGenerateSlides}
                          disabled={generatingSlides || generatingNotes}
                          className="bg-[#4242EA] hover:bg-[#3535D1] font-proxima"
                        >
                          <Presentation className="h-4 w-4 mr-1" />
                          {generatingSlides ? 'Generating...' : 'Generate Slides'}
                        </Button>
                        {canEdit && (
                          <>
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={handleEditDayGoals}
                              className="font-proxima"
                            >
                              <Edit className="h-4 w-4 mr-1" />
                              Edit Goals
                            </Button>
                            <Button
                              size="sm"
                              variant="destructive"
                              onClick={handleDeleteDay}
                              className="font-proxima"
                            >
                              <Trash2 className="h-4 w-4 mr-1" />
                              Delete Day
                            </Button>
                          </>
                        )}
                      </div>
                    </div>

                    {dayContent.day?.daily_goal && (
                      <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                        <h3 className="font-semibold text-blue-900 mb-2 font-proxima">
                          Daily Goal
                        </h3>
                        <p className="text-blue-800 font-proxima">
                          {dayContent.day.daily_goal}
                        </p>
                      </div>
                    )}
                  </div>

                  {/* Tasks */}
                  <div className="space-y-6">
                    <div className="flex items-center justify-between">
                      <h2 className="text-xl font-bold text-slate-900 font-proxima">
                        Tasks ({dayContent.flattenedTasks?.length || 0})
                      </h2>
                      {canEdit && (
                        <Button
                          size="sm"
                          onClick={handleAddTask}
                          className="bg-blue-600 hover:bg-blue-700 text-white font-proxima"
                        >
                          <Plus className="h-4 w-4 mr-1" />
                          Add Task
                        </Button>
                      )}
                    </div>
                    {dayContent.flattenedTasks && dayContent.flattenedTasks.length > 0 ? (
                      <div className="grid gap-4">
                        {dayContent.flattenedTasks.map((task) => (
                          <TaskCard
                            key={task.id}
                            task={task}
                            onEdit={handleEditTask}
                            onDelete={handleDeleteTask}
                            onViewHistory={handleViewHistory}
                            canEdit={canEdit}
                          />
                        ))}
                      </div>
                    ) : (
                      <div className="text-center py-12 text-slate-500 font-proxima">
                        No tasks found for this day
                      </div>
                    )}
                  </div>

                  {/* Enter Interactive Mode CTA */}
                  <div className="mt-8 p-6 bg-blue-50 border border-blue-200 rounded-lg text-center">
                    <h3 className="text-lg font-bold text-blue-900 mb-2 font-proxima">
                      Ready to test the content?
                    </h3>
                    <p className="text-blue-700 mb-4 font-proxima">
                      Enter interactive mode to experience this day exactly as students see it - including AI chat, deliverable submissions, and more.
                    </p>
                    <button
                      onClick={() => setPreviewMode('interactive')}
                      className="bg-blue-600 text-white px-6 py-2 rounded-lg font-semibold font-proxima hover:bg-blue-700 transition-colors"
                    >
                      ▶ Enter Interactive Mode
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Editing Dialogs */}
        <TaskEditDialog
          open={editDialogOpen}
          onOpenChange={setEditDialogOpen}
          task={selectedTask}
          onSave={handleSaveTask}
          onViewFieldHistory={handleViewFieldHistory}
          onMoveTask={() => setMoveTaskDialogOpen(true)}
          canEdit={canEdit}
          token={token}
        />

        <FieldHistoryDialog
          open={historyDialogOpen}
          onOpenChange={setHistoryDialogOpen}
          fieldName={selectedField}
          entityType={selectedEntityType}
          entityId={selectedEntityId}
          onRevert={handleRevertField}
          canEdit={canEdit}
        />

        <DayGoalEditor
          open={goalEditorOpen}
          onOpenChange={setGoalEditorOpen}
          day={selectedDay}
          week={null}
          onSave={handleSaveGoals}
          onViewFieldHistory={handleViewFieldHistory}
          canEdit={canEdit}
        />

        <MoveTaskDialog
          open={moveTaskDialogOpen}
          onOpenChange={setMoveTaskDialogOpen}
          task={selectedTask}
          currentDay={selectedDay}
          allDays={[]} // Would need to pass available days from cohort
          onMove={handleMoveTask}
        />

        <TaskCreateDialog
          open={createTaskDialogOpen}
          onOpenChange={setCreateTaskDialogOpen}
          onSave={handleCreateTask}
          dayNumber={dayContent?.day?.day_number}
          token={token}
        />

        {/* Delete Task Confirmation Dialog */}
        <AlertDialog open={deleteTaskDialogOpen} onOpenChange={setDeleteTaskDialogOpen}>
          <AlertDialogContent className="font-proxima">
            <AlertDialogHeader>
              <AlertDialogTitle>Delete Task?</AlertDialogTitle>
              <AlertDialogDescription>
                Are you sure you want to delete <strong>{taskToDelete?.task_title}</strong>?
                <br /><br />
                This will permanently delete:
                <ul className="list-disc list-inside mt-2 ml-2">
                  <li>The task and all its content</li>
                  <li>All student submissions for this task</li>
                  <li>All conversations related to this task</li>
                </ul>
                <br />
                <strong>This action cannot be undone.</strong>
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancel</AlertDialogCancel>
              <AlertDialogAction
                onClick={confirmDeleteTask}
                className="bg-red-600 hover:bg-red-700"
              >
                Delete Task
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Delete Day Confirmation Dialog */}
        <AlertDialog open={deleteDayDialogOpen} onOpenChange={setDeleteDayDialogOpen}>
          <AlertDialogContent className="font-proxima">
            <AlertDialogHeader>
              <AlertDialogTitle>Delete Curriculum Day?</AlertDialogTitle>
              <AlertDialogDescription>
                Are you sure you want to delete{' '}
                <strong>Day {dayToDelete?.day_number}</strong>
                {dayToDelete?.day_date && (
                  <> ({new Date(dayToDelete.day_date).toLocaleDateString('en-US', {
                    month: 'short',
                    day: 'numeric',
                    year: 'numeric'
                  })})</>
                )}?
                <br /><br />
                This will permanently delete:
                <ul className="list-disc list-inside mt-2 ml-2">
                  <li>All time blocks for this day</li>
                  <li>All tasks for this day</li>
                  <li>All task submissions and conversations</li>
                </ul>
                <br />
                <strong>This action cannot be undone.</strong>
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Cancel</AlertDialogCancel>
              <AlertDialogAction
                onClick={confirmDeleteDay}
                className="bg-red-600 hover:bg-red-700"
              >
                Delete Day
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Curriculum Upload Dialog */}
        <CurriculumUploadDialog
          open={uploadDialogOpen}
          onOpenChange={setUploadDialogOpen}
          cohort={uploadCohort}
          token={token}
          onUploadComplete={handleUploadComplete}
        />
      </div>
    </>
  );
}

export default ContentPreview;
